def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / cap
        if ratio > 1:
            priorities[i] = float('inf')
            continue
        score = 0
        for j in range(1, 10):
            threshold = j * 0.1
            if ratio < threshold:
                score += (10 - j) * (1 - ratio**2) + j * np.sin(ratio * np.pi)
            elif ratio < threshold + 0.05:
                score += (j * np.cos(np.pi * ratio)) / (j + 1)
            else:
                score += j * ratio / (j + 2)
        if cap % 3 == 0:
            score *= np.exp(-ratio) * np.log1p(cap)
        elif cap % 2 == 0:
            score *= np.sqrt(cap) / (cap + 1)
        else:
            score *= (np.tanh(cap / (item + 1)) + 1) / 2
        if cap > 50:
            bonus = 0
            for k in range(1, 5):
                if ratio < 0.1 * k:
                    bonus += (5 - k) * np.exp(-k * ratio)
                else:
                    bonus += k * np.log1p(ratio + k)
            score += bonus / cap
        priorities[i] = score
    return priorities
